1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Array<Item> };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<QuoteStep> };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const countByType = (items: Item[]): Record<string, number> => {
24	  const counts: Record<string, number> = {};
25	  for (const item of items) {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	  }
28	  return counts;
29	};
30	
31	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
32	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
33	
34	const typeBase = (type: string, count: number): number =>
35	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
36	
37	const policyBaseFor = (items: Item[]): number =>
38	  sum(Object.entries(countByType(items)).map(([type, count]) => typeBase(type, count)));
39	
40	const quotePremium = (step: QuoteStep): number => {
41	  const policyBase = policyBaseFor(step.items);
42	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
43	  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
44	};
45	
46	export const runScenario = (input: unknown): unknown => {
47	  const scenario = input as Scenario;
48	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
49	  return { results };
50	};
